            {result.isProfitable ? '✓ Прибыльно' : '✗ Убыточно'}
          </p>
        </div>
        {result.bepUnits != null && result.isProfitable && (
          <div className="text-center py-2 bg-accent rounded-md">
            <p className="text-xs text-muted-foreground">BEP</p>
